    private val raw: String = CHUNK_0 +
        CHUNK_1 +
        CHUNK_2 +
        CHUNK_3 +
        CHUNK_4

    // Display name -> numeric id, in the site's alphabetical order.
    val pairs: List<Pair<String, String>> by lazy {
        raw.lineSequence().mapNotNull { line ->
            val tab = line.indexOf('\t')
            if (tab <= 0) return@mapNotNull null
            line.substring(0, tab) to line.substring(tab + 1)
        }.toList()
    }
